вектор<int> поредок (јазол* корен) {
    вектор<int> резултат;
    if (root == nullptr) {
        повратен резултат;
    }

    // Преминете ги сите деца
    за (Јазол* дете : корен-> деца) {
        вектор<int> childValues = поредок (дете);
        result.insert(result.end(), childValues.begin(), childValues.end());
    }

    // Додадете ја вредноста на коренот
    result.push_back(root->val);
    повратен резултат;
}
```

Овде, вршиме рекурзивна поредна траверза на n-ary дрвото. Најпрво рекурзивно ги поминуваме сите деца на јазолот, а потоа ја додаваме вредноста на тековниот јазол на резултатот од преминувањето по редослед.

Почнуваме од коренот на дрвото и продолжуваме да ја повикуваме функцијата `postorder` рекурзивно на секое дете од јазолот. Откако ќе го имаме преминувањето на поредок на сите деца, едноставно ја додаваме вредноста на тековниот јазол на векторот на резултатот и го враќаме.

